import{_ as t,c as a,o,a5 as c,eC as s,gr as r,gs as i,eM as l,eL as d}from"./chunks/framework.BgIqBWih.js";const _=JSON.parse('{"title":"Magic Paste (Quick Tutorial)","description":"","frontmatter":{},"headers":[],"relativePath":"docs/tutorial/tuto-magic-paste.md","filePath":"docs/tutorial/tuto-magic-paste.md","lastUpdated":1772777937000}'),n={name:"docs/tutorial/tuto-magic-paste.md"};function h(p,e,m,u,f,w){return o(),a("div",null,[...e[0]||(e[0]=[c('<h1 id="magic-paste-quick-tutorial" tabindex="-1">Magic Paste (Quick Tutorial) <a class="header-anchor" href="#magic-paste-quick-tutorial" aria-label="Permalink to “Magic Paste (Quick Tutorial)”">​</a></h1><h2 id="what-is-magic-paste" tabindex="-1">What is Magic Paste? <a class="header-anchor" href="#what-is-magic-paste" aria-label="Permalink to “What is Magic Paste?”">​</a></h2><p>Magic Paste in Liii STEM can paste structured content from plain text, webpages, PDFs, handwritten formulas, and screenshots with near-lossless accuracy. It recognizes formulas, tables, code blocks, and document structure automatically.</p><h2 id="how-to-use-it" tabindex="-1">How to use it <a class="header-anchor" href="#how-to-use-it" aria-label="Permalink to “How to use it”">​</a></h2><blockquote><p>On macOS, replace <code>Ctrl</code> with <code>Command</code>.</p></blockquote><h3 id="select-ctrl-c-ctrl-v" tabindex="-1">Select -&gt; <code>Ctrl</code> + <code>C</code> -&gt; <code>Ctrl</code> + <code>V</code> <a class="header-anchor" href="#select-ctrl-c-ctrl-v" aria-label="Permalink to “Select -&gt; Ctrl + C -&gt; Ctrl + V”">​</a></h3><p><img src="'+s+'" alt=""></p><p>Copy content from webpages or other sources, then paste with <code>Ctrl</code> + <code>V</code>.</p><h3 id="copy-markdown-latex-ctrl-shift-v" tabindex="-1">Copy Markdown/LaTeX -&gt; <code>Ctrl</code> + <code>Shift</code> + <code>V</code> <a class="header-anchor" href="#copy-markdown-latex-ctrl-shift-v" aria-label="Permalink to “Copy Markdown/LaTeX -&gt; Ctrl + Shift + V”">​</a></h3><p>Common ways to copy Markdown/LaTeX:</p><ol><li>Select text and press <code>Ctrl</code> + <code>C</code>.</li><li>Use the copy button in an LLM chat tool (content is often copied as Markdown/LaTeX).</li></ol><div class="flex flex-col sm:flex-row justify-center gap-4"><img src="'+r+'" alt="Copy as Markdown" class="w-full sm:w-1/2" style="max-width:400px;"><img src="'+i+'" alt="Lossless paste" class="w-full sm:w-1/2" style="max-width:400px;"></div><p>Then paste with <code>Ctrl</code> + <code>Shift</code> + <code>V</code>.</p><h3 id="screenshot-ctrl-shift-v" tabindex="-1">Screenshot -&gt; <code>Ctrl</code> + <code>Shift</code> + <code>V</code> <a class="header-anchor" href="#screenshot-ctrl-shift-v" aria-label="Permalink to “Screenshot -&gt; Ctrl + Shift + V”">​</a></h3><p>Make sure the screenshot is in your clipboard, then press <code>Ctrl</code> + <code>Shift</code> + <code>V</code>.</p><div class="flex flex-col sm:flex-row justify-center gap-4"><img src="'+l+'" alt="Paste handwritten formulas" class="w-full sm:w-1/2" style="max-width:300px;"><img src="'+d+'" alt="Paste image from webpage" class="w-full sm:w-1/2" style="max-width:300px;"></div><blockquote><p>Windows: use <code>PrintScreen</code>. macOS: use <code>Command</code> + <code>Ctrl</code> + <code>Shift</code> + <code>4</code>.</p></blockquote>',17)])])}const x=t(n,[["render",h]]);export{_ as __pageData,x as default};
